import "dotenv/config";
import { AppServer, TpaSession } from '@mentra/sdk';
import { callKaiAPI, translateText, detectLanguage, userIdToSpeakerKey, KaiResponse } from './kai-client';

const PACKAGE_NAME = process.env.PACKAGE_NAME || 'com.kai.glasses';
const MENTRA_API_KEY = process.env.MENTRA_API_KEY || '';
const PORT = parseInt(process.env.PORT || '3000');
const DEFAULT_TARGET_LANG = process.env.TARGET_LANG || 'English';
const USER_LANG_CODE = process.env.USER_LANG_CODE || 'en';

// SSE clients — one per browser tab watching the webview
const sseClients = new Set<any>();

// Broadcast an event to all connected webview browsers
function broadcast(event: string, data: object) {
  const payload = `event: ${event}\ndata: ${JSON.stringify(data)}\n\n`;
  sseClients.forEach(res => {
    try { res.write(payload); } catch {}
  });
}

const translationMode = new Map<string, boolean>();
const sessionTargetLang = new Map<string, string>();

function isTranslateCommand(text: string): boolean {
  const t = text.toLowerCase();
  return t.includes('translate') || t.includes('traducir') || t.includes('traduire');
}

function isTranslateModeToggle(text: string): { toggle: boolean; on: boolean } {
  const t = text.toLowerCase();
  if (t.includes('translation on') || t.includes('translate on') || t.includes('start translating')) return { toggle: true, on: true };
  if (t.includes('translation off') || t.includes('translate off') || t.includes('stop translating')) return { toggle: true, on: false };
  return { toggle: false, on: false };
}

class KaiApp extends AppServer {
  constructor() {
    super({ packageName: PACKAGE_NAME, apiKey: MENTRA_API_KEY, port: PORT });

    const app = (this as any).app;

    // SSE endpoint — browser connects here for live updates
    app.get('/events', (req: any, res: any) => {
      res.setHeader('Content-Type', 'text/event-stream');
      res.setHeader('Cache-Control', 'no-cache');
      res.setHeader('Connection', 'keep-alive');
      res.setHeader('Access-Control-Allow-Origin', '*');
      res.flushHeaders();
      res.write(`event: status\ndata: ${JSON.stringify({ state: 'ready', translation_mode: false })}\n\n`);
      sseClients.add(res);
      req.on('close', () => sseClients.delete(res));
    });

    // Webview page
    app.get('/webview', (_req: any, res: any) => res.send(WEBVIEW_HTML));
    app.get('/', (_req: any, res: any) => res.send(WEBVIEW_HTML));
  }

  protected async onSession(
    session: TpaSession,
    sessionId: string,
    userId: string
  ): Promise<void> {
    console.log(`\n🟢 KAI session started — user: ${userId}`);
    const speakerKey = userIdToSpeakerKey(userId);
    const targetLang = sessionTargetLang.get(sessionId) || DEFAULT_TARGET_LANG;

    await session.layouts.showTextWall('KAI is ready 👋');
    broadcast('status', { state: 'ready', translation_mode: translationMode.get(sessionId) || false });
    setTimeout(() => session.layouts.showTextWall(''), 2000);

    session.events.onTranscription(async (data) => {
      const userText = data.text?.trim();
      if (!userText || userText.length < 2) return;

      if (!data.isFinal) {
        session.layouts.showTextWall(`🎙️ "${userText}"`);
        return;
      }

      console.log(`\n👤 User said: "${userText}"`);
      broadcast('user', { text: userText });

      // Translation mode toggle
      const modeToggle = isTranslateModeToggle(userText);
      if (modeToggle.toggle) {
        translationMode.set(sessionId, modeToggle.on);
        const msg = modeToggle.on ? '🌍 Translation mode ON' : '🔇 Translation mode OFF';
        await session.layouts.showTextWall(msg);
        broadcast('status', { state: 'ready', translation_mode: modeToggle.on });
        broadcast('reply', { text: msg });
        return;
      }

      // Explicit translate command
      if (isTranslateCommand(userText)) {
        const match = userText.match(/translate\s+(.+)/i) || userText.match(/traducir\s+(.+)/i);
        const textToTranslate = match ? match[1] : userText;
        await session.layouts.showTextWall('🌍 Translating...');
        broadcast('status', { state: 'translating' });
        try {
          const result = await translateText(textToTranslate, targetLang, speakerKey);
          const display = result.is_same_language
            ? `Already in ${targetLang}: "${result.translation}"`
            : `[${result.detected_language} → ${targetLang}]\n${result.translation}`;
          console.log(`🌍 Translated: "${result.original}" → "${result.translation}"`);
          await session.layouts.showTextWall(display);
          broadcast('translation', result);
          broadcast('status', { state: 'ready' });
          setTimeout(() => session.layouts.showTextWall(''), 10000);
        } catch (error) {
          console.error('Translation error:', error);
          await session.layouts.showTextWall('Translation failed.');
          broadcast('reply', { text: 'Translation failed. Try again.' });
          broadcast('status', { state: 'ready' });
        }
        return;
      }

      // Auto-translation mode
      if (translationMode.get(sessionId)) {
        broadcast('status', { state: 'translating' });
        try {
          const detected = await detectLanguage(userText);
          if (detected.language_code !== USER_LANG_CODE && detected.confidence !== 'low') {
            const result = await translateText(userText, targetLang, speakerKey);
            const display = `[${result.detected_language}]\n${result.translation}`;
            console.log(`🌍 Auto-translated from ${result.detected_language}: "${result.translation}"`);
            await session.layouts.showTextWall(display);
            broadcast('translation', result);
            broadcast('status', { state: 'ready' });
            setTimeout(() => session.layouts.showTextWall(''), 10000);
            return;
          }
        } catch {}
      }

      // Normal KAI conversation
      await session.layouts.showTextWall('KAI is thinking...');
      broadcast('status', { state: 'thinking' });
      try {
        const response: KaiResponse = await callKaiAPI(userText, sessionId, userId);
        const replyText = response.text || response.response || 'Sorry, I had trouble with that.';
        console.log(`🤖 KAI replied: "${replyText}"`);
        await session.layouts.showTextWall(replyText);
        broadcast('reply', { text: replyText });
        broadcast('status', { state: 'ready' });
        setTimeout(() => session.layouts.showTextWall(''), 8000);
      } catch (error) {
        console.error('❌ Error calling KAI API:', error);
        await session.layouts.showTextWall('Connection error. Try again.');
        broadcast('reply', { text: 'Connection error. Try again.' });
        broadcast('status', { state: 'ready' });
      }
    });
  }
}

const app = new KaiApp();
app.start()
  .then(() => {
    console.log(`\n🚀 KAI MiniApp running on port ${PORT}`);
    console.log(`📦 Package: ${PACKAGE_NAME}`);
    console.log(`🌍 Default translation target: ${DEFAULT_TARGET_LANG}`);
    console.log(`🔗 Waiting for Mentra connections...\n`);
  })
  .catch((err) => {
    console.error('Failed to start KAI MiniApp:', err);
    process.exit(1);
  });

const WEBVIEW_HTML = `<!DOCTYPE html>
<html lang="en">
<head>
<meta name="viewport" content="width=device-width,initial-scale=1,maximum-scale=1">
<title>KAI</title>
<link href="https://fonts.googleapis.com/css2?family=Rajdhani:wght@300;400;600;700&family=Share+Tech+Mono&display=swap" rel="stylesheet">
<style>
  :root {
    --kai-blue: #4fc3f7;
    --kai-glow: rgba(79,195,247,0.15);
    --kai-dim: rgba(79,195,247,0.4);
    --bg: #020408;
    --surface: rgba(255,255,255,0.03);
    --border: rgba(79,195,247,0.12);
  }

  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    background: var(--bg);
    color: #e8f4fd;
    font-family: 'Rajdhani', sans-serif;
    height: 100vh;
    display: flex;
    flex-direction: column;
    overflow: hidden;
  }

  /* Animated background grid */
  body::before {
    content: '';
    position: fixed;
    inset: 0;
    background-image:
      linear-gradient(rgba(79,195,247,0.03) 1px, transparent 1px),
      linear-gradient(90deg, rgba(79,195,247,0.03) 1px, transparent 1px);
    background-size: 40px 40px;
    pointer-events: none;
    z-index: 0;
  }

  /* Header */
  .header {
    position: relative;
    z-index: 10;
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 16px 20px 12px;
    border-bottom: 1px solid var(--border);
    background: rgba(2,4,8,0.8);
    backdrop-filter: blur(20px);
  }

  .logo {
    width: 36px;
    height: 36px;
    object-fit: contain;
    filter: drop-shadow(0 0 8px var(--kai-blue));
  }

  .brand {
    flex: 1;
  }

  .brand-name {
    font-size: 1.4em;
    font-weight: 700;
    letter-spacing: 4px;
    background: linear-gradient(135deg, #fff 0%, var(--kai-blue) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
  }

  .brand-sub {
    font-family: 'Share Tech Mono', monospace;
    font-size: 0.6em;
    color: var(--kai-dim);
    letter-spacing: 2px;
  }

  /* Status indicator */
  .status {
    display: flex;
    align-items: center;
    gap: 6px;
    font-family: 'Share Tech Mono', monospace;
    font-size: 0.65em;
    color: var(--kai-dim);
    letter-spacing: 1px;
  }

  .status-dot {
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background: var(--kai-blue);
    box-shadow: 0 0 6px var(--kai-blue);
    animation: pulse 2s infinite;
  }

  .status-dot.thinking {
    background: #ffd54f;
    box-shadow: 0 0 6px #ffd54f;
    animation: blink 0.5s infinite;
  }

  .status-dot.translating {
    background: #a5d6a7;
    box-shadow: 0 0 6px #a5d6a7;
    animation: blink 0.3s infinite;
  }

  @keyframes pulse {
    0%, 100% { opacity: 1; transform: scale(1); }
    50% { opacity: 0.5; transform: scale(0.8); }
  }

  @keyframes blink {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.2; }
  }

  /* Conversation area */
  .conversation {
    flex: 1;
    overflow-y: auto;
    padding: 16px;
    display: flex;
    flex-direction: column;
    gap: 12px;
    position: relative;
    z-index: 1;
  }

  .conversation::-webkit-scrollbar { width: 2px; }
  .conversation::-webkit-scrollbar-track { background: transparent; }
  .conversation::-webkit-scrollbar-thumb { background: var(--border); border-radius: 2px; }

  /* Empty state */
  .empty-state {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 12px;
    opacity: 0.3;
    padding: 40px;
    text-align: center;
  }

  .empty-state img {
    width: 80px;
    opacity: 0.5;
    filter: grayscale(1);
  }

  .empty-state p {
    font-family: 'Share Tech Mono', monospace;
    font-size: 0.75em;
    letter-spacing: 2px;
    color: var(--kai-dim);
  }

  /* Message bubbles */
  .message {
    display: flex;
    flex-direction: column;
    gap: 4px;
    animation: slideIn 0.3s ease-out;
  }

  @keyframes slideIn {
    from { opacity: 0; transform: translateY(8px); }
    to { opacity: 1; transform: translateY(0); }
  }

  .message.user { align-items: flex-end; }
  .message.kai { align-items: flex-start; }
  .message.translation { align-items: flex-start; }

  .message-label {
    font-family: 'Share Tech Mono', monospace;
    font-size: 0.55em;
    letter-spacing: 2px;
    color: var(--kai-dim);
    padding: 0 4px;
  }

  .message.user .message-label { color: rgba(255,255,255,0.3); }

  .bubble {
    max-width: 85%;
    padding: 10px 14px;
    border-radius: 2px;
    font-size: 0.95em;
    font-weight: 400;
    line-height: 1.5;
    letter-spacing: 0.5px;
    position: relative;
  }

  .message.user .bubble {
    background: rgba(255,255,255,0.06);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 12px 2px 12px 12px;
    color: rgba(255,255,255,0.75);
  }

  .message.kai .bubble {
    background: rgba(79,195,247,0.08);
    border: 1px solid rgba(79,195,247,0.2);
    border-radius: 2px 12px 12px 12px;
    color: #e8f4fd;
    box-shadow: 0 0 20px rgba(79,195,247,0.05);
  }

  .message.translation .bubble {
    background: rgba(165,214,167,0.06);
    border: 1px solid rgba(165,214,167,0.2);
    border-radius: 2px 12px 12px 12px;
    color: #e8f5e9;
  }

  .translation-tag {
    display: inline-block;
    font-family: 'Share Tech Mono', monospace;
    font-size: 0.65em;
    letter-spacing: 1px;
    color: #a5d6a7;
    background: rgba(165,214,167,0.1);
    padding: 2px 6px;
    border-radius: 2px;
    margin-bottom: 6px;
  }

  /* Thinking indicator */
  .thinking-bubble {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 10px 14px;
    background: rgba(79,195,247,0.05);
    border: 1px solid rgba(79,195,247,0.1);
    border-radius: 2px 12px 12px 12px;
    animation: slideIn 0.3s ease-out;
  }

  .thinking-dot {
    width: 5px;
    height: 5px;
    border-radius: 50%;
    background: var(--kai-blue);
    animation: thinkingDot 1.2s infinite;
  }

  .thinking-dot:nth-child(2) { animation-delay: 0.2s; }
  .thinking-dot:nth-child(3) { animation-delay: 0.4s; }

  @keyframes thinkingDot {
    0%, 60%, 100% { opacity: 0.2; transform: scale(0.8); }
    30% { opacity: 1; transform: scale(1.2); }
  }

  /* Bottom bar */
  .bottom-bar {
    position: relative;
    z-index: 10;
    padding: 12px 20px;
    border-top: 1px solid var(--border);
    background: rgba(2,4,8,0.8);
    backdrop-filter: blur(20px);
    display: flex;
    align-items: center;
    justify-content: space-between;
  }

  .mode-pill {
    font-family: 'Share Tech Mono', monospace;
    font-size: 0.6em;
    letter-spacing: 1.5px;
    padding: 4px 10px;
    border-radius: 20px;
    border: 1px solid var(--border);
    color: var(--kai-dim);
  }

  .mode-pill.active {
    border-color: #a5d6a7;
    color: #a5d6a7;
    background: rgba(165,214,167,0.08);
  }

  .timestamp {
    font-family: 'Share Tech Mono', monospace;
    font-size: 0.6em;
    color: rgba(255,255,255,0.15);
    letter-spacing: 1px;
  }
</style>
</head>
<body>

<div class="header">
  <img class="logo" src="data:image/png;base64," alt="KAI">
  <div class="brand">
    <div class="brand-name">KAI</div>
    <div class="brand-sub">VOICE AI SYSTEM</div>
  </div>
  <div class="status">
    <div class="status-dot" id="statusDot"></div>
    <span id="statusText">READY</span>
  </div>
</div>

<div class="conversation" id="conversation">
  <div class="empty-state" id="emptyState">
    <img src="data:image/png;base64," alt="">
    <p>SPEAK TO BEGIN</p>
  </div>
</div>

<div class="bottom-bar">
  <div class="mode-pill" id="translationPill">TRANSLATION OFF</div>
  <div class="timestamp" id="clock"></div>
</div>

<script>
const LOGO = '';
document.querySelectorAll('img').forEach(img => {
  if (img.src.includes('')) img.src = 'data:image/png;base64,' + LOGO;
});

const conv = document.getElementById('conversation');
const emptyState = document.getElementById('emptyState');
const statusDot = document.getElementById('statusDot');
const statusText = document.getElementById('statusText');
const translationPill = document.getElementById('translationPill');
let thinkingEl = null;
let translationMode = false;

// Clock
function updateClock() {
  document.getElementById('clock').textContent = new Date().toLocaleTimeString('en-US', {hour:'2-digit',minute:'2-digit',hour12:false});
}
updateClock();
setInterval(updateClock, 1000);

function hideEmpty() {
  if (emptyState) emptyState.style.display = 'none';
}

function scrollBottom() {
  conv.scrollTop = conv.scrollHeight;
}

function addMessage(type, text, extra) {
  hideEmpty();
  removeThinking();
  const msg = document.createElement('div');
  msg.className = 'message ' + type;

  if (type === 'user') {
    msg.innerHTML = '<div class="message-label">YOU</div><div class="bubble">' + escHtml(text) + '</div>';
  } else if (type === 'kai') {
    msg.innerHTML = '<div class="message-label">KAI</div><div class="bubble">' + escHtml(text) + '</div>';
  } else if (type === 'translation') {
    const tag = extra ? '<div class="translation-tag">' + escHtml(extra) + ' → EN</div>' : '';
    msg.innerHTML = '<div class="message-label">TRANSLATION</div><div class="bubble">' + tag + escHtml(text) + '</div>';
  }

  conv.appendChild(msg);
  scrollBottom();
}

function showThinking() {
  hideEmpty();
  removeThinking();
  thinkingEl = document.createElement('div');
  thinkingEl.className = 'message kai';
  thinkingEl.innerHTML = '<div class="message-label">KAI</div><div class="thinking-bubble"><div class="thinking-dot"></div><div class="thinking-dot"></div><div class="thinking-dot"></div></div>';
  conv.appendChild(thinkingEl);
  scrollBottom();
}

function removeThinking() {
  if (thinkingEl) { thinkingEl.remove(); thinkingEl = null; }
}

function setStatus(state) {
  statusDot.className = 'status-dot ' + (state !== 'ready' ? state : '');
  statusText.textContent = state.toUpperCase();
}

function escHtml(t) {
  return t.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

// SSE connection
function connect() {
  const es = new EventSource('/events');

  es.addEventListener('user', e => {
    const d = JSON.parse(e.data);
    addMessage('user', d.text);
    showThinking();
    setStatus('thinking');
  });

  es.addEventListener('reply', e => {
    const d = JSON.parse(e.data);
    addMessage('kai', d.text);
    setStatus('ready');
  });

  es.addEventListener('translation', e => {
    const d = JSON.parse(e.data);
    addMessage('translation', d.translation, d.detected_language);
    setStatus('ready');
  });

  es.addEventListener('status', e => {
    const d = JSON.parse(e.data);
    setStatus(d.state);
    if (d.state === 'thinking') showThinking();
    if (d.translation_mode !== undefined) {
      translationMode = d.translation_mode;
      translationPill.textContent = translationMode ? 'TRANSLATION ON' : 'TRANSLATION OFF';
      translationPill.className = 'mode-pill' + (translationMode ? ' active' : '');
    }
  });

  es.onerror = () => {
    setStatus('reconnecting');
    setTimeout(connect, 3000);
    es.close();
  };
}

connect();
</script>
</body>
</html>`;
